/* 2. Expanding Card Styles */
.expand-card {
  background-color: #f8fafc;
  border: 1px solid #e2e8f0;
  border-radius: 16px;
  padding: 16px;
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.card-badge {
  align-self: flex-start;
  background-color: #ef4444;
  color: #ffffff;
  font-size: 10px;
  font-weight: 700;
  padding: 3px 8px;
  border-radius: 20px;
}

.card-preview {
  font-size: 13px;
  line-height: 1.5;
  color: #475569;
}

.card-full-content {
  max-height: 0;
  overflow: hidden;
  transition: max-height 0.35s ease;
}

.card-full-inner {
  padding-top: 10px;
  border-top: 1px dashed #cbd5e1;
  font-size: 13px;
  line-height: 1.6;
  color: #475569;
}

.btn-card-expand {
  width: 100%;
  padding: 12px;
  background-color: #ffffff;
  border: 1px solid #cbd5e1;
  border-radius: 10px;
  font-weight: 600;
  cursor: pointer;
}
